using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { ID = 1, LastName = "Smith", FirstMidName = "Alice", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { ID = 2, LastName = "Jones", FirstMidName = "Bob", EnrollmentDate = new DateTime(2021, 1, 15) },
                new Student { ID = 3, LastName = "Adams", FirstMidName = "Charlie", EnrollmentDate = new DateTime(2020, 9, 1) }
            );
            context.SaveChanges();
        }

        public static void SeedDepartments(SchoolContext context)
        {
            context.Departments.AddRange(
                new Department { DepartmentID = 1, Name = "English", Budget = 100000m, StartDate = new DateTime(2010, 1, 1), RowVersion = new byte[] { 0, 0, 0, 1 } },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 200000m, StartDate = new DateTime(2011, 1, 1), RowVersion = new byte[] { 0, 0, 0, 2 } }
            );
            context.SaveChanges();
        }

        public static void SeedCourses(SchoolContext context)
        {
            SeedDepartments(context);
            context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 }
            );
            context.SaveChanges();
        }

        public static void SeedInstructors(SchoolContext context)
        {
            context.Instructors.AddRange(
                new Instructor
                {
                    ID = 10,
                    LastName = "Zheng",
                    FirstMidName = "Roger",
                    HireDate = new DateTime(2004, 2, 12),
                    CourseAssignments = new List<CourseAssignment>(),
                    OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
                },
                new Instructor
                {
                    ID = 11,
                    LastName = "Kapoor",
                    FirstMidName = "Candace",
                    HireDate = new DateTime(2001, 1, 15),
                    CourseAssignments = new List<CourseAssignment>()
                }
            );
            context.SaveChanges();
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            // Drain the static queue to avoid cross-test contamination
            _sut = new NotificationService();
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Student 'Alice Smith' has been created")]
        [DataRow(EntityOperation.UPDATE, "Student 'Alice Smith' has been updated")]
        [DataRow(EntityOperation.DELETE, "Student 'Alice Smith' has been deleted")]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage(EntityOperation operation, string expectedMessage)
        {
            // Act
            _sut.SendNotification("Student", "1", "Alice Smith", operation, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(expectedMessage, notification.Message);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual(operation.ToString(), notification.Operation);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Student (ID: 42) has been created")]
        [DataRow(EntityOperation.UPDATE, "Student (ID: 42) has been updated")]
        [DataRow(EntityOperation.DELETE, "Student (ID: 42) has been deleted")]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage(EntityOperation operation, string expectedMessage)
        {
            // Act
            _sut.SendNotification("Student", "42", operation);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(expectedMessage, notification.Message);
        }

        [TestMethod]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            // Act
            _sut.SendNotification("Course", "101", "Calculus", EntityOperation.CREATE, null);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleSent_ReturnsFIFO()
        {
            // Arrange
            _sut.SendNotification("A", "1", "First", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE);

            // Act & Assert
            var first = _sut.ReceiveNotification();
            Assert.AreEqual("A", first.EntityType);

            var second = _sut.ReceiveNotification();
            Assert.AreEqual("B", second.EntityType);

            Assert.IsNull(_sut.ReceiveNotification());
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtTimestamp()
        {
            // Act
            var before = System.DateTime.Now;
            _sut.SendNotification("Dept", "1", "Math", EntityOperation.CREATE, "User1");
            var after = System.DateTime.Now;

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op in the in-memory implementation
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            // Should not throw
            _sut.Dispose();
            _sut.Dispose();
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsProperties()
        {
            // Arrange
            var items = new List<string> { "a", "b", "c" };

            // Act
            var list = new PaginatedList<string>(items, 10, 2, 3);

            // Assert
            Assert.AreEqual(2, list.PageIndex);
            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
            Assert.AreEqual(3, list.Count);
            CollectionAssert.AreEqual(items, list.ToList());
        }

        [TestMethod]
        [DataRow(1, false, true, DisplayName = "First page has next, no previous")]
        [DataRow(2, true, true, DisplayName = "Middle page has both")]
        [DataRow(4, true, false, DisplayName = "Last page has previous, no next")]
        public void HasPreviousPage_HasNextPage_CorrectForPage(int pageIndex, bool expectPrevious, bool expectNext)
        {
            // 10 items, page size 3 => 4 pages
            var list = new PaginatedList<int>(new List<int>(), 10, pageIndex, 3);

            Assert.AreEqual(expectPrevious, list.HasPreviousPage);
            Assert.AreEqual(expectNext, list.HasNextPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPage()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var page = PaginatedList<int>.Create(source, 2, 10);

            // Assert
            Assert.AreEqual(2, page.PageIndex);
            Assert.AreEqual(3, page.TotalPages); // ceil(25/10)
            Assert.AreEqual(10, page.Count);
            Assert.AreEqual(11, page[0]);
            Assert.AreEqual(20, page[9]);
        }

        [TestMethod]
        public void Create_LastPartialPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 7).AsQueryable();

            // Act
            var page = PaginatedList<int>.Create(source, 2, 5);

            // Assert
            Assert.AreEqual(2, page.PageIndex);
            Assert.AreEqual(2, page.TotalPages);
            Assert.AreEqual(2, page.Count);
            Assert.AreEqual(6, page[0]);
            Assert.AreEqual(7, page[1]);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var page = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(0, page.Count);
            Assert.AreEqual(0, page.TotalPages);
            Assert.IsFalse(page.HasPreviousPage);
            Assert.IsFalse(page.HasNextPage);
        }

        [TestMethod]
        public void Create_SinglePage_NoNavigationNeeded()
        {
            // Arrange
            var source = Enumerable.Range(1, 5).AsQueryable();

            // Act
            var page = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(1, page.TotalPages);
            Assert.AreEqual(5, page.Count);
            Assert.IsFalse(page.HasPreviousPage);
            Assert.IsFalse(page.HasNextPage);
        }
    }
}

