using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            // Drain the static queue to avoid cross-test contamination
            _sut = new NotificationService();
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Student 'Alice Smith' has been created")]
        [DataRow(EntityOperation.UPDATE, "Student 'Alice Smith' has been updated")]
        [DataRow(EntityOperation.DELETE, "Student 'Alice Smith' has been deleted")]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage(EntityOperation operation, string expectedMessage)
        {
            // Act
            _sut.SendNotification("Student", "1", "Alice Smith", operation, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(expectedMessage, notification.Message);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual(operation.ToString(), notification.Operation);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Student (ID: 42) has been created")]
        [DataRow(EntityOperation.UPDATE, "Student (ID: 42) has been updated")]
        [DataRow(EntityOperation.DELETE, "Student (ID: 42) has been deleted")]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage(EntityOperation operation, string expectedMessage)
        {
            // Act
            _sut.SendNotification("Student", "42", operation);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(expectedMessage, notification.Message);
        }

        [TestMethod]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            // Act
            _sut.SendNotification("Course", "101", "Calculus", EntityOperation.CREATE, null);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleSent_ReturnsFIFO()
        {
            // Arrange
            _sut.SendNotification("A", "1", "First", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE);

            // Act & Assert
            var first = _sut.ReceiveNotification();
            Assert.AreEqual("A", first.EntityType);

            var second = _sut.ReceiveNotification();
            Assert.AreEqual("B", second.EntityType);

            Assert.IsNull(_sut.ReceiveNotification());
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtTimestamp()
        {
            // Act
            var before = System.DateTime.Now;
            _sut.SendNotification("Dept", "1", "Math", EntityOperation.CREATE, "User1");
            var after = System.DateTime.Now;

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op in the in-memory implementation
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            // Should not throw
            _sut.Dispose();
            _sut.Dispose();
        }
    }
}

