using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsProperties()
        {
            // Arrange
            var items = new List<string> { "a", "b", "c" };

            // Act
            var list = new PaginatedList<string>(items, 10, 2, 3);

            // Assert
            Assert.AreEqual(2, list.PageIndex);
            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
            Assert.AreEqual(3, list.Count);
            CollectionAssert.AreEqual(items, list.ToList());
        }

        [TestMethod]
        [DataRow(1, false, true, DisplayName = "First page has next, no previous")]
        [DataRow(2, true, true, DisplayName = "Middle page has both")]
        [DataRow(4, true, false, DisplayName = "Last page has previous, no next")]
        public void HasPreviousPage_HasNextPage_CorrectForPage(int pageIndex, bool expectPrevious, bool expectNext)
        {
            // 10 items, page size 3 => 4 pages
            var list = new PaginatedList<int>(new List<int>(), 10, pageIndex, 3);

            Assert.AreEqual(expectPrevious, list.HasPreviousPage);
            Assert.AreEqual(expectNext, list.HasNextPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPage()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var page = PaginatedList<int>.Create(source, 2, 10);

            // Assert
            Assert.AreEqual(2, page.PageIndex);
            Assert.AreEqual(3, page.TotalPages); // ceil(25/10)
            Assert.AreEqual(10, page.Count);
            Assert.AreEqual(11, page[0]);
            Assert.AreEqual(20, page[9]);
        }

        [TestMethod]
        public void Create_LastPartialPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 7).AsQueryable();

            // Act
            var page = PaginatedList<int>.Create(source, 2, 5);

            // Assert
            Assert.AreEqual(2, page.PageIndex);
            Assert.AreEqual(2, page.TotalPages);
            Assert.AreEqual(2, page.Count);
            Assert.AreEqual(6, page[0]);
            Assert.AreEqual(7, page[1]);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var page = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(0, page.Count);
            Assert.AreEqual(0, page.TotalPages);
            Assert.IsFalse(page.HasPreviousPage);
            Assert.IsFalse(page.HasNextPage);
        }

        [TestMethod]
        public void Create_SinglePage_NoNavigationNeeded()
        {
            // Arrange
            var source = Enumerable.Range(1, 5).AsQueryable();

            // Act
            var page = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(1, page.TotalPages);
            Assert.AreEqual(5, page.Count);
            Assert.IsFalse(page.HasPreviousPage);
            Assert.IsFalse(page.HasNextPage);
        }
    }
}

