namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new NotificationsController(_context);

            // Drain any existing notifications
            var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
            svc.Dispose();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            var result = _controller.GetNotifications() as JsonResult;

            Assert.IsNotNull(result);
            var value = result.Value;
            // Use reflection to check dynamic anonymous type properties
            var successProp = value.GetType().GetProperty("success");
            var countProp = value.GetType().GetProperty("count");
            Assert.IsTrue((bool)successProp.GetValue(value));
            Assert.AreEqual(0, (int)countProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_WithQueuedNotifications_ReturnsNotifications()
        {
            // Arrange - enqueue some notifications
            var svc = new NotificationService();
            svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");
            svc.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE, "Admin");
            svc.Dispose();

            // Act
            var result = _controller.GetNotifications() as JsonResult;

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            var countProp = value.GetType().GetProperty("count");
            Assert.IsTrue((bool)successProp.GetValue(value));
            Assert.AreEqual(2, (int)countProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_LimitsToTenNotifications()
        {
            // Arrange - enqueue more than 10
            var svc = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                svc.SendNotification("Entity", i.ToString(), $"Item {i}", EntityOperation.CREATE, "Admin");
            }
            svc.Dispose();

            // Act
            var result = _controller.GetNotifications() as JsonResult;

            // Assert
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.AreEqual(10, (int)countProp.GetValue(value));
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1) as JsonResult;

            Assert.IsNotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.IsTrue((bool)successProp.GetValue(value));
        }
    }
}
