using System;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedStudents(_context);
            _controller = new StudentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        #region Index

        [TestMethod]
        public void Index_NoParameters_ReturnsViewWithAllStudentsOrderedByLastName()
        {
            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
            // Default sort is by LastName ascending: Adams, Jones, Smith
            Assert.AreEqual("Adams", model[0].LastName);
            Assert.AreEqual("Jones", model[1].LastName);
            Assert.AreEqual("Smith", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_ReturnsDescendingOrder()
        {
            // Act
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual("Smith", model[0].LastName);
            Assert.AreEqual("Jones", model[1].LastName);
            Assert.AreEqual("Adams", model[2].LastName);
        }

        [TestMethod]
        public void Index_DateSort_ReturnsOrderedByEnrollmentDate()
        {
            // Act
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            // 2020-09-01 (Adams or Smith), 2020-09-01, 2021-01-15 (Jones)
            Assert.AreEqual("Jones", model[2].LastName);
        }

        [TestMethod]
        public void Index_DateDescSort_ReturnsDescendingByDate()
        {
            // Act
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual("Jones", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchString_FiltersResults()
        {
            // Act
            var result = _controller.Index(null, null, "Smith", null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Smith", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchStringByFirstName_FiltersResults()
        {
            // Act
            var result = _controller.Index(null, null, "Alice", null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alice", model[0].FirstMidName);
        }

        [TestMethod]
        public void Index_NewSearchString_ResetsPageTo1()
        {
            // When searchString is not null, page should be 1
            var result = _controller.Index(null, null, "Adams", 5) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            // When searchString is null, it uses currentFilter
            var result = _controller.Index(null, "Jones", null, null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Jones", model[0].LastName);
        }

        [TestMethod]
        public void Index_SetsViewBagSortParameters()
        {
            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
            Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
        }

        [TestMethod]
        public void Index_WhenSortIsDate_DateSortParmIsDateDesc()
        {
            _controller.Index("Date", null, null, null);
            Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            // Arrange - need enrollments for Include
            var enrollment = new Enrollment { CourseID = 1, StudentID = 1 };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            // Act
            var result = _controller.Details(1) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual("Smith", model.LastName);
        }

        #endregion

        #region Create

        [TestMethod]
        public void Create_Get_ReturnsViewWithStudentDefaultDate()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        [TestMethod]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            // Act
            var result = _controller.Create(student) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(4, _context.Students.Count());
        }

        [TestMethod]
        public void Create_Post_MinValueEnrollmentDate_ReturnsViewWithError()
        {
            // Arrange
            var student = new Student
            {
                LastName = "Bad",
                FirstMidName = "Date",
                EnrollmentDate = DateTime.MinValue
            };

            // Act
            var result = _controller.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsFalse(_controller.ModelState.IsValid);
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                EnrollmentDate = new DateTime(2023, 1, 1)
            };

            // Act
            var result = _controller.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual(student, result.Model);
        }

        #endregion

        #region Edit

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null) as StatusCodeResult;
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999) as NotFoundResult;
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Edit(1) as ViewResult;
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.AreEqual("Smith", model.LastName);
        }

        [TestMethod]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var student = new Student
            {
                ID = 1,
                LastName = "UpdatedSmith",
                FirstMidName = "Alice",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };
            // Detach the existing tracked entity
            var tracked = _context.Students.Find(1);
            _context.Entry(tracked).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            // Act
            var result = _controller.Edit(student) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_DefaultEnrollmentDate_AddsModelError()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "Alice",
                EnrollmentDate = default
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        #endregion

        #region Delete

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999) as NotFoundResult;
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Delete(1) as ViewResult;
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.AreEqual("Smith", model.LastName);
        }

        [TestMethod]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            // Act
            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(2, _context.Students.Count());
        }

        #endregion
    }
}

