using System.Collections.Generic;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        private SchoolContext _context;
        private HomeController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedStudents(_context);
            _controller = new HomeController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void About_ReturnsViewWithEnrollmentGroups()
        {
            var result = _controller.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            // We have students with 2 distinct enrollment dates
            Assert.AreEqual(2, model.Count);
            // 2020-09-01 has 2 students (Adams, Smith)
            var group2020 = model.First(g => g.EnrollmentDate == new System.DateTime(2020, 9, 1));
            Assert.AreEqual(2, group2020.StudentCount);
        }

        [TestMethod]
        public void Contact_SetsViewBagMessage()
        {
            var result = _controller.Contact() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsView()
        {
            var result = _controller.Error() as ViewResult;
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Unauthorized_SetsViewBagMessage()
        {
            var result = _controller.Unauthorized() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

