using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class CoursesControllerTests
    {
        private SchoolContext _context;
        private CoursesController _controller;
        private Mock<IWebHostEnvironment> _mockEnv;
        private Mock<ILogger<CoursesController>> _mockLogger;
        private string _tempDir;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedCourses(_context);

            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);

            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _mockLogger = new Mock<ILogger<CoursesController>>();

            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
            if (Directory.Exists(_tempDir))
                Directory.Delete(_tempDir, true);
        }

        #region Index

        [TestMethod]
        public void Index_ReturnsViewWithAllCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<Course>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1050) as ViewResult;
            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.AreEqual("Chemistry", model.Title);
        }

        #endregion

        #region Create

        [TestMethod]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            var result = _controller.Create() as ViewResult;
            Assert.IsNotNull(result);
            Assert.IsNotNull(_controller.ViewBag.DepartmentID);
        }

        [TestMethod]
        public void Create_Post_ValidCourseNoImage_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(3, _context.Courses.Count());
        }

        [TestMethod]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 8888 };

            var result = _controller.Create(course, null) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsNotNull(_controller.ViewBag.DepartmentID);
        }

        [TestMethod]
        public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            var course = new Course { CourseID = 7777, Title = "Test", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFormFile("test.exe", 1000);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Create_Post_FileTooLarge_ReturnsViewWithError()
        {
            var course = new Course { CourseID = 7778, Title = "Test", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFormFile("test.jpg", 6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Create_Post_ValidImage_SavesFileAndRedirects()
        {
            var course = new Course { CourseID = 7779, Title = "With Image", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFormFile("photo.png", 1024);

            var result = _controller.Create(course, mockFile.Object) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            var savedCourse = _context.Courses.Find(7779);
            Assert.IsTrue(savedCourse.TeachingMaterialImagePath.StartsWith("/Uploads/TeachingMaterials/"));
        }

        #endregion

        #region Edit

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null) as StatusCodeResult;
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999) as NotFoundResult;
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit(1050) as ViewResult;
            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.AreEqual("Chemistry", model.Title);
        }

        [TestMethod]
        public void Edit_Post_ValidCourseNoImage_RedirectsToIndex()
        {
            var existing = _context.Courses.Find(1050);
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var course = new Course
            {
                CourseID = 1050,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _controller.Edit(course, null) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            var existing = _context.Courses.Find(1050);
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFormFile("bad.txt", 500);

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Edit_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050 };

            var result = _controller.Edit(course, null) as ViewResult;

