using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class InstructorsControllerTests
    {
        private SchoolContext _context;
        private InstructorsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedCourses(_context); // seeds departments too
            TestHelpers.SeedInstructors(_context);

            // Add course assignments for instructor 10
            _context.CourseAssignments.Add(new CourseAssignment { InstructorID = 10, CourseID = 1050 });
            _context.SaveChanges();

            _controller = new InstructorsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        #region Index

        [TestMethod]
        public void Index_NoParameters_ReturnsViewWithInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Instructors.Count());
        }

        [TestMethod]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var result = _controller.Index(10, null) as ViewResult;

            var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model.Courses);
            Assert.AreEqual(1, model.Courses.Count());
        }

        [TestMethod]
        public void Index_WithCourseId_PopulatesEnrollments()
        {
            // Add an enrollment for course 1050
            _context.Students.Add(new Student { ID = 100, LastName = "Test", FirstMidName = "Stud", EnrollmentDate = DateTime.Now });
            _context.SaveChanges();
            _context.Enrollments.Add(new Enrollment { CourseID = 1050, StudentID = 100 });
            _context.SaveChanges();

            var result = _controller.Index(10, 1050) as ViewResult;

            var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model.Enrollments);
            Assert.AreEqual(1, model.Enrollments.Count());
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999) as NotFoundResult;
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Details(10) as ViewResult;
            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.AreEqual("Zheng", model.LastName);
        }

        #endregion

        #region Create

        [TestMethod]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;
            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.CourseAssignments);
        }

        [TestMethod]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewProf",
                FirstMidName = "Jane",
                HireDate = new DateTime(2022, 8, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Create_Post_WithSelectedCourses_CreatesCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "CourseProf",
